#include <bits/stdc++.h>
using namespace std;

const int MAX = 102; // 1-indexed, add border
bool grid[MAX+2][MAX+2]; // grid[x][y]
bool visited[MAX+2][MAX+2];

int dx[4] = {0, 0, 1, -1};
int dy[4] = {1, -1, 0, 0};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;
    for (int i = 0; i < N; i++) {
        int x, y;
        cin >> x >> y;
        grid[x][y] = true;
    }

    // BFS from outside (0,0) to find all empty cells reachable from the outer border
    // Use a 102x102 grid (1..100 are actual field cells, 0 and 101 are border)
    queue<pair<int,int>> q;
    q.push({0, 0});
    visited[0][0] = true;

    while (!q.empty()) {
        auto [cx, cy] = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nx = cx + dx[d];
            int ny = cy + dy[d];
            if (nx < 0 || nx > MAX+1 || ny < 0 || ny > MAX+1) continue;
            if (visited[nx][ny]) continue;
            if (grid[nx][ny]) continue; // hay bale blocks
            visited[nx][ny] = true;
            q.push({nx, ny});
        }
    }

    // Now compute perimeter: For each hay bale cell, count edges adjacent to
    // cells that are NOT hay bales AND are reachable from outside (i.e., not holes).
    int perimeter = 0;
    for (int x = 1; x <= 100; x++) {
        for (int y = 1; y <= 100; y++) {
            if (!grid[x][y]) continue;
            for (int d = 0; d < 4; d++) {
                int nx = x + dx[d];
                int ny = y + dy[d];
                // If neighbor is outside the grid or is not a hay bale and is reachable from outside
                if (nx < 1 || nx > 100 || ny < 1 || ny > 100) {
                    // border of field counts as outside
                    perimeter++;
                } else if (!grid[nx][ny] && visited[nx][ny]) {
                    perimeter++;
                }
            }
        }
    }

    cout << perimeter << "\n";
    return 0;
}
